#include<string>
#include<iostream>
#include<algorithm>
using namespace std;

const int N = 30;
struct Node
{
	int lch, rch;
}tree[N];

string preorder(string mid, string post)
{
	int n = mid.size();
	if(n <= 1) return mid;
	int p = -1;
	for(int i = 0; i < n; i++)
		if(mid[i] == post[n - 1])
			p = i;
	string ans;
	ans += post[n - 1];
	ans += preorder(mid.substr(0, p), post.substr(0, p));
	ans += preorder(mid.substr(p + 1), post.substr(p, n - p - 1));
	return ans;
}

int main(){
	string mid, post;
	cin >> mid >> post;
	cout << preorder(mid, post);
	return 0;
}
